                        type: 'breakdown',
                        compound: compound,
                        question: `Which roots form "${compound.form}"?`,
                        display: compound.form,
                        correct: compound.roots.join(' + '),
                        options: generateBreakdownOptions(compound.roots)
                    });
                });
            }

            return shuffleArray(qs);
        }

        function generateOptions(correct, pool) {
            const options = [correct];
            const wrong = pool.filter(p => p !== correct);
            while (options.length < 4 && wrong.length > 0) {
                const idx = Math.floor(Math.random() * wrong.length);
                const opt = wrong.splice(idx, 1)[0];
                if (!options.includes(opt)) options.push(opt);
            }
            return shuffleArray(options);
        }

        function generateBreakdownOptions(correctRoots) {
            const correct = correctRoots.join(' + ');
            const options = [correct];

            while (options.length < 4) {
                const randomRoots = shuffleArray([...roots]).slice(0, 3);
                const wrong = randomRoots.map(r => r.form).join(' + ');
                if (!options.includes(wrong)) options.push(wrong);
            }

            return shuffleArray(options);
        }

        function shuffleArray(array) {
            const newArray = [...array];
            for (let i = newArray.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
            }
            return newArray;
        }

        function showQuestion() {
            if (currentQuestion >= questions.length) {
                questionText.textContent = `Quiz Complete! Final Score: ${Math.round((correct/total)*100)}%`;
                wordDisplay.classList.add('hidden');
                wordBreakdown.classList.add('hidden');
                optionsDiv.innerHTML = '<button class="btn" onclick="resetQuiz()">Restart</button>';
                nextBtn.classList.add('hidden');
                return;
            }

            answered = false;
            const q = questions[currentQuestion];

            feedbackDiv.classList.add('hidden');
            nextBtn.classList.add('hidden');
            wordDisplay.classList.add('hidden');
            wordBreakdown.classList.add('hidden');

            questionText.textContent = q.question;

            if (q.display) {
                wordDisplay.textContent = q.display;
                wordDisplay.classList.remove('hidden');
            }

            if (q.compound && currentMode === 'compounds') {
                wordBreakdown.innerHTML = q.compound.roots.map(r => {
                    const root = roots.find(root => root.form === r);
                    return `
                        <div class="morpheme">
                            <div class="form">${r}</div>
                            <div class="meaning">${root?.meaning || '?'}</div>
                        </div>
                    `;
                }).join('');
                wordBreakdown.classList.remove('hidden');
            }

            optionsDiv.innerHTML = q.options.map((opt, idx) => `
                <div class="option" data-idx="${idx}" onclick="selectOption(${idx})">${opt}</div>
            `).join('');

            document.getElementById('questionCard').classList.add('fade-in');
            setTimeout(() => document.getElementById('questionCard').classList.remove('fade-in'), 500);
        }

        function selectOption(idx) {
            if (answered) return;
            answered = true;
            total++;

            const q = questions[currentQuestion];
            const selected = q.options[idx];
            const isCorrect = selected === q.correct;

            if (isCorrect) {
                correct++;
                streak++;
            } else {
                streak = 0;
            }
            updateStats();

            const options = document.querySelectorAll('.option');
            options.forEach((opt, i) => {
                opt.classList.add('disabled');
                if (q.options[i] === q.correct) opt.classList.add('correct');
                else if (i === idx && !isCorrect) opt.classList.add('incorrect');
            });

            feedbackDiv.textContent = isCorrect ? `Correct! ${q.correct}` : `The answer is: ${q.correct}`;
            feedbackDiv.className = `feedback ${isCorrect ? 'correct' : 'incorrect'}`;
            feedbackDiv.classList.remove('hidden');

            nextBtn.classList.remove('hidden');
            nextBtn.textContent = currentQuestion < questions.length - 1 ? 'Next Question' : 'See Results';
            nextBtn.onclick = () => {
                currentQuestion++;
                updateProgressBar();
                showQuestion();
            };
        }

        function updateStats() {
            document.getElementById('correctCount').textContent = correct;
            document.getElementById('streakCount').textContent = streak;
            document.getElementById('accuracyCount').textContent = total > 0 ? Math.round((correct / total) * 100) + '%' : '0%';
        }

        function updateProgressBar() {
            const dots = questions.map((_, i) => {
                let cls = 'progress-dot';
                if (i < currentQuestion) cls += ' completed';
                else if (i === currentQuestion) cls += ' current';
                return `<div class="${cls}"></div>`;
            }).join('');
            document.getElementById('progressBar').innerHTML = dots;
        }

        // Start
        init();
    </script>
</body>
</html>
